;// CONCATENATED MODULE: ./server/_core/context.ts

async function createContext(opts) {
    let user = null;
    try {
        user = await sdk.authenticateRequest(opts.req);
    }
    catch (error) {
        // Authentication is optional for public procedures.
        user = null;
    }
    return {
        req: opts.req,
        res: opts.res,
        user,
    };
}

;// CONCATENATED MODULE: ./server-api/index.ts
console.log("[Server] Arquivo api/index.ts carregado com sucesso!");






// Cache do app para evitar recriar em cada requisição na Vercel
let appCache = null;
async function getApp() {
    if (appCache)
        return appCache;
    const app = express_default()();
    app.use(express_default().json({ limit: "50mb" }));
    app.use(express_default().urlencoded({ limit: "50mb", extended: true }));
    // Rota de teste para ver se o servidor ligou
    app.get(["/api/health", "/health"], (req, res) => {
        res.json({
            status: "ok",
            message: "Servidor ativo!",
            env: process.env.NODE_ENV,
            db_configured: !!process.env.DATABASE_URL
        });
    });
    // Rotas de autenticação
    registerOAuthRoutes(app);
    registerLocalAuthRoutes(app);
    // tRPC API
    app.use(["/api/trpc", "/trpc"], createExpressMiddleware({
        router: appRouter,
        createContext: createContext,
    }));
    appCache = app;
    // Debug: capturar rotas que não batem com nada
    app.use((req, res) => {
        console.log(`[Express] Rota não encontrada: ${req.method} ${req.url}`);
        res.status(404).json({
            error: "Rota não encontrada no Express",
            method: req.method,
            url: req.url,
            registered_routes: ["/api/health", "/api/trpc", "/api/auth/login", "/api/auth/google", "/health", "/trpc", "/auth/login", "/auth/google"]
        });
    });
    return app;
}
async function handler(req, res) {
    try {
        const app = await getApp();
        return app(req, res);
    }
    catch (error) {
        console.error("Critical Server Error:", error);
        res.status(500).json({
            error: "Internal Server Error",
            message: error.message,
            stack: process.env.NODE_ENV === "development" ? error.stack : undefined
        });
    }
}

